// Normalize message | edited_message | callback_query into one shape.
const u = $input.first().json;
const cb = u.callback_query || null;
const msg = u.message || u.edited_message || (cb && cb.message) || {};
const isCallback = !!cb;
let text = isCallback ? (cb.data || '') : (msg.text || msg.caption || '');
text = String(text);
const chatId = (msg.chat && msg.chat.id) || (cb && cb.from && cb.from.id) || '';
const updateId = (u.update_id !== undefined && u.update_id !== null) ? u.update_id : 0;
return [{ json: { update_id: updateId, chat_id: chatId, message_id: (msg.message_id || null), text: text, kind: isCallback ? 'callback_query' : (u.edited_message ? 'edited_message' : 'message') } }];

